// ── Test data paths ───────────────────────────────────────────────────────────

static fs::path TESTDATA  = fs::path(__FILE__).parent_path() / "testdata";
static fs::path IMG_DIR   = TESTDATA / "images";
static fs::path VID_DIR   = TESTDATA / "videos";
static fs::path TMP_DIR   = fs::temp_directory_path() / "batchpress_test";

// ── Fixture ───────────────────────────────────────────────────────────────────

class BPTest : public ::testing::Test {
protected:
    void SetUp() override {
        fs::remove_all(TMP_DIR);
        fs::create_directories(TMP_DIR);
    }
    void TearDown() override { fs::remove_all(TMP_DIR); }

    bool skip_if_missing(const fs::path& dir) {
        if (!fs::exists(dir)) {
            std::cout << "  [SKIP] testdata not found: " << dir << "\n"
                      << "  Run generate_test_images.py and "
                         "generate_test_videos.sh first.\n";
            return true;
        }
        return false;
    }

    fs::path first_file(const fs::path& dir, const std::string& ext,
                        uint64_t max_bytes = UINT64_MAX) {
        for (const auto& e : fs::recursive_directory_iterator(dir)) {
            if (!e.is_regular_file()) continue;
            std::string ex = e.path().extension().string();
            std::transform(ex.begin(), ex.end(), ex.begin(), ::tolower);
            if (ex == ext && e.file_size() <= max_bytes)
                return e.path();
        }
        return {};
    }

    size_t count_files(const fs::path& dir) {
        size_t n = 0;
        for (const auto& e : fs::recursive_directory_iterator(dir))
            if (e.is_regular_file()) ++n;
        return n;
    }
};

