TEST_F(BPTest, Images_CollectFindsAllFormats) {
    if (skip_if_missing(IMG_DIR)) GTEST_SKIP();

    Config cfg;
    cfg.input_dir = IMG_DIR;
    cfg.recursive = true;
    auto imgs = collect_images(cfg);

    ASSERT_GT(imgs.size(), 0u);

    bool jpg=false, png=false, bmp=false;
    for (const auto& p : imgs) {
        std::string ext = p.extension().string();
        std::transform(ext.begin(), ext.end(), ext.begin(), ::tolower);
        if (ext==".jpg"||ext==".jpeg") jpg=true;
        if (ext==".png") png=true;
        if (ext==".bmp") bmp=true;
    }
    EXPECT_TRUE(jpg) << "No JPG found";
    EXPECT_TRUE(png) << "No PNG found";
    EXPECT_TRUE(bmp) << "No BMP found";

    std::cout << "  Found " << imgs.size() << " images (jpg/png/bmp ✓)\n";
}

