TEST_F(BPTest, Images_DryRun_SourceUnchanged) {
    if (skip_if_missing(IMG_DIR)) GTEST_SKIP();

    fs::path src = first_file(IMG_DIR, ".jpg");
    if (src.empty()) GTEST_SKIP();

    uint64_t orig_size = fs::file_size(src);

    Config cfg;
    cfg.input_dir = IMG_DIR;
    cfg.output_dir= IMG_DIR;
    cfg.dry_run   = true;
    cfg.format    = ImageFormat::WebP;
    cfg.quality   = 40;
    cfg.resize    = parse_resize("10%");

    TaskResult r = process_image(src, cfg);
    EXPECT_TRUE(r.success);
    EXPECT_TRUE(r.dry_run);
    EXPECT_GT(r.output_bytes, 0u)   << "Dry-run must return size estimate";
    EXPECT_EQ(fs::file_size(src), orig_size) << "Dry-run modified source file!";

    // No output written
    fs::path out = r.output_path;
    if (out != src) { EXPECT_FALSE(fs::exists(out)) << "Dry-run created output!"; }

    std::cout << "  Dry-run: " << orig_size/1024 << " KB → estimated "
              << r.output_bytes/1024 << " KB\n";
}

TEST_F(BPTest, Images_BatchCopy_AllSucceed) {
    if (skip_if_missing(IMG_DIR)) GTEST_SKIP();

    Config cfg;
    cfg.input_dir  = IMG_DIR;
    cfg.output_dir = TMP_DIR / "batch";
    cfg.format     = ImageFormat::WebP;
    cfg.quality    = 50;       // Low quality to ensure significant compression
    cfg.resize     = parse_resize("fit:1280x720");
    cfg.recursive  = true;

    uint32_t cb = 0;
    cfg.on_progress = [&](const TaskResult&, uint32_t, uint32_t){ ++cb; };

    BatchReport r = run_batch(cfg);

    EXPECT_EQ(r.failed, 0u)      << r.failed << " images failed";
    EXPECT_GT(r.succeeded, 0u);
    EXPECT_EQ(cb, r.total)       << "Progress callback not called for all tasks";
    // Note: WebP at quality 50 should be smaller than mixed format originals
    // If this fails, it means some originals were already highly compressed

    std::cout << "  Batch: " << r.total << " images"
              << "  " << r.input_bytes_total/1024 << " KB"
              << " → " << r.output_bytes_total/1024 << " KB"
              << "  (" << std::fixed << std::setprecision(1)
              << r.savings_pct() << "% saved)\n";
}

