TEST_F(BPTest, Images_InPlace_ReducesSize) {
    if (skip_if_missing(IMG_DIR)) GTEST_SKIP();

    // Clean TMP_DIR first
    fs::remove_all(TMP_DIR);
    fs::create_directories(TMP_DIR);

    // Copy a large JPG to tmp and process in-place (changes extension to WebP)
    fs::path src = first_file(IMG_DIR, ".jpg");
    if (src.empty()) GTEST_SKIP();

    fs::path copy = TMP_DIR / "inplace.jpg";
    fs::copy_file(src, copy);
    uint64_t orig = fs::file_size(copy);

    Config cfg;
    cfg.input_dir  = TMP_DIR;
    cfg.output_dir = "";       // in-place
    cfg.format     = ImageFormat::WebP;
    cfg.quality    = 70;
    cfg.recursive  = false;

    BatchReport r = run_batch(cfg);
    EXPECT_EQ(r.failed, 0u);

    // After in-place processing with format change, extension changes
    fs::path out = copy; 
    out.replace_extension(".webp");
    ASSERT_TRUE(fs::exists(out)) << "In-place output not found: " << out;
    EXPECT_GT(fs::file_size(out), 0u);

    // Original JPG should no longer exist (replaced by WebP)
    EXPECT_FALSE(fs::exists(copy)) << "Original should be replaced";

    std::cout << "  In-place: " << orig/1024 << " KB (JPG)"
              << " → " << fs::file_size(out)/1024 << " KB (WebP)\n";
}

TEST_F(BPTest, Images_InPlace_NoExtraFiles) {
    if (skip_if_missing(IMG_DIR)) GTEST_SKIP();

    // Test that in-place processing does not leave extra files behind
    fs::path src = first_file(IMG_DIR, ".jpg");
    if (src.empty()) GTEST_SKIP();

    fs::path copy = TMP_DIR / "inplace_test.jpg";
    fs::copy_file(src, copy);
    
    // Count files before processing
    size_t files_before = count_files(TMP_DIR);
    
    Config cfg;
    cfg.input_dir  = TMP_DIR;
    cfg.output_dir = "";       // in-place
    cfg.format     = ImageFormat::WebP;
    cfg.quality    = 70;
    cfg.recursive  = false;

    BatchReport r = run_batch(cfg);
    EXPECT_EQ(r.failed, 0u);
    
    // Count files after processing
    size_t files_after = count_files(TMP_DIR);
    
    // Should have same number of files (original replaced, not added)
    // Note: extension changes from .jpg to .webp, so we check no temp files remain
    EXPECT_EQ(files_after, files_before) 
        << "In-place processing should not create extra files";
    
    // Verify no temporary files left behind
    for (const auto& e : fs::recursive_directory_iterator(TMP_DIR)) {
        std::string fname = e.path().filename().string();
        EXPECT_EQ(fname.find(".batchpress.tmp"), std::string::npos) 
            << "Temporary file found after completion: " << e.path();
    }
    
    std::cout << "  In-place: " << files_before << " files before → " 
              << files_after << " files after (no extras ✓)\n";
}

TEST_F(BPTest, Images_InPlace_DirectMode_HashRecorded) {
    if (skip_if_missing(IMG_DIR)) GTEST_SKIP();

    // Test that Direct mode (forced via env var) records SHA-256 hash
    fs::path src = first_file(IMG_DIR, ".jpg", 500*1024); // Small file ≤500KB
    if (src.empty()) GTEST_SKIP();

    fs::path copy = TMP_DIR / "direct_test.jpg";
    fs::copy_file(src, copy);
    uint64_t orig_size = fs::file_size(copy);

    // Force Direct mode via environment variable
    setenv("BATCHPRESS_FORCE_DIRECT", "1", 1);

    Config cfg;
    cfg.input_dir  = TMP_DIR;
    cfg.output_dir = "";       // in-place
    cfg.format     = ImageFormat::WebP;
    cfg.quality    = 85;
    cfg.recursive  = false;

    TaskResult result = process_image(copy, cfg);

    // Clean up environment variable
    unsetenv("BATCHPRESS_FORCE_DIRECT");

    EXPECT_TRUE(result.success) << result.error_msg;
    EXPECT_GT(result.output_bytes, 0u);

    // Direct mode MUST record SHA-256 for recovery
    EXPECT_EQ(result.write_mode, WriteMode::Direct)
        << "Direct mode should be forced by env var";
    EXPECT_FALSE(result.original_sha256.empty())
        << "Direct mode must record SHA-256 for recovery";
    EXPECT_EQ(result.original_sha256.length(), 64u)
        << "SHA-256 hash should be 64 hex characters";

    std::cout << "  Direct mode used: hash=" 
              << result.original_sha256.substr(0, 16) << "...\n";
    std::cout << "  Direct/Safe test: " << orig_size/1024 << " KB → " 
              << result.output_bytes/1024 << " KB  mode=Direct ✓\n";
}

TEST_F(BPTest, Images_InPlace_VerifyOutputIntegrity) {
    if (skip_if_missing(IMG_DIR)) GTEST_SKIP();

    // Verify that in-place processed file can be loaded back as valid image
    fs::path src = first_file(IMG_DIR, ".png");
    if (src.empty()) GTEST_SKIP();

    fs::path copy = TMP_DIR / "integrity_test.png";
    fs::copy_file(src, copy);

    Config cfg;
    cfg.input_dir  = TMP_DIR;
    cfg.output_dir = "";       // in-place
    cfg.format     = ImageFormat::JPEG;
    cfg.quality    = 80;
    cfg.recursive  = false;

    TaskResult result = process_image(copy, cfg);
    EXPECT_TRUE(result.success) << result.error_msg;
    
    fs::path out = copy;
    out.replace_extension(".jpg");
    ASSERT_TRUE(fs::exists(out)) << "Output file not found";
    
    // Try to load the output file to verify it's a valid image
    int w=0, h=0, ch=0;
    unsigned char* pixels = stbi_load(out.string().c_str(), &w, &h, &ch, 0);
    EXPECT_NE(pixels, nullptr) 
        << "Output file is not a valid image: " << stbi_failure_reason();
    EXPECT_GT(w, 0);
    EXPECT_GT(h, 0);
    EXPECT_GT(ch, 0);
    
    if (pixels) stbi_image_free(pixels);
    
    std::cout << "  Integrity check: output is valid " 
              << w << "x" << h << "x" << ch << " image ✓\n";
}

