TEST_F(BPTest, Scan_ProducesReport) {
    if (skip_if_missing(IMG_DIR)) GTEST_SKIP();

    ScanConfig cfg;
    cfg.root_dir        = IMG_DIR;
    cfg.recursive       = true;
    cfg.samples_per_dir = 3;

    uint32_t cb = 0;
    cfg.on_progress = [&](const std::string&, uint32_t, uint32_t){ ++cb; };

    ScanReport r = run_scan(cfg);
    EXPECT_GT(r.total_images, 0u);
    EXPECT_GT(r.total_bytes,  0u);
    EXPECT_GT(r.directories.size(), 0u);
    EXPECT_GT(r.savings_pct(), 0.0);
    EXPECT_GT(cb, 0u);

    std::string cmd = r.suggested_command();
    EXPECT_FALSE(cmd.empty());
    EXPECT_NE(cmd.find("batchpress"), std::string::npos);

    std::cout << "  Scan: " << r.total_images << " images"
              << "  " << r.directories.size() << " dirs"
              << "  projected " << std::fixed << std::setprecision(1)
              << r.savings_pct() << "% saving\n";
    std::cout << "  Suggested: " << cmd << "\n";
}

TEST_F(BPTest, Scan_CandidatesSortedBySavings) {
    if (skip_if_missing(IMG_DIR)) GTEST_SKIP();

    ScanConfig cfg;
    cfg.root_dir        = IMG_DIR;
    cfg.recursive       = true;
    cfg.samples_per_dir = 3;

    ScanReport r = run_scan(cfg);
    for (const auto& dir : r.directories) {
        for (size_t i = 1; i < dir.candidates.size(); ++i) {
            EXPECT_LE(dir.candidates[i].savings_pct,
                      dir.candidates[i-1].savings_pct + 0.01)
                << "Candidates not sorted descending in " << dir.directory;
        }
    }
}

