TEST_F(BPTest, Video_CopyMode_ProducesOutput) {
    if (skip_if_missing(VID_DIR)) GTEST_SKIP();

    // Use smallest video for speed
    fs::path src = first_file(VID_DIR, ".mp4", 3*1024*1024);
    if (src.empty()) GTEST_SKIP() << "No small MP4 (≤3MB) in testdata";

    VideoConfig cfg;
    cfg.input_dir  = VID_DIR;
    cfg.output_dir = TMP_DIR / "vid_out";
    cfg.video_codec= VideoCodec::Auto;
    cfg.resolution = ResolutionCap::Cap1080p;
    cfg.dry_run    = false;

    uint32_t frame_cb = 0;
    cfg.on_progress = [&](const fs::path&, uint64_t, uint64_t,
                          uint32_t, uint32_t){ ++frame_cb; };

    VideoResult r = process_video(src, cfg);
    EXPECT_TRUE(r.success)          << r.error_msg;
    EXPECT_TRUE(fs::exists(r.output_path));
    EXPECT_GT(r.output_bytes, 0u);
    EXPECT_GT(frame_cb, 0u)        << "Frame callback never called";

    std::cout << "  Video transcode: " << src.filename()
              << "  " << r.input_bytes/1024 << " KB"
              << " → " << r.output_bytes/1024 << " KB"
              << "  codec=" << static_cast<int>(r.codec_used)
              << "  crf=" << r.crf_used << "\n";
}

TEST_F(BPTest, Video_ScanReport) {
    if (skip_if_missing(VID_DIR)) GTEST_SKIP();

    VideoScanConfig cfg;
    cfg.root_dir  = VID_DIR;
    cfg.recursive = true;

    uint32_t cb = 0;
    cfg.on_progress = [&](const std::string&, uint32_t, uint32_t){ ++cb; };

    VideoScanReport r = run_video_scan(cfg);
    if (r.total_videos == 0) GTEST_SKIP() << "No videos in testdata";

    EXPECT_GT(r.total_bytes, 0u);
    EXPECT_GT(r.directories.size(), 0u);
    EXPECT_GT(r.savings_pct(), 0.0);
    EXPECT_GT(cb, 0u);
    EXPECT_FALSE(r.suggested_command().empty());

    std::cout << "  Video scan: " << r.total_videos << " videos"
              << "  " << r.total_bytes/(1024*1024) << " MB"
              << "  projected " << std::fixed << std::setprecision(1)
              << r.savings_pct() << "% saving\n";
    std::cout << "  Suggested: " << r.suggested_command() << "\n";
}

TEST_F(BPTest, Video_BatchDryRun) {
    if (skip_if_missing(VID_DIR)) GTEST_SKIP();

    VideoConfig cfg;
    cfg.input_dir  = VID_DIR;
    cfg.output_dir = TMP_DIR;
    cfg.dry_run    = true;
    cfg.recursive  = true;

    VideoBatchReport r = run_video_batch(cfg);
    if (r.total == 0) GTEST_SKIP() << "No videos in testdata";

    EXPECT_TRUE(r.dry_run);
    EXPECT_EQ(r.failed, 0u);
    EXPECT_GT(r.succeeded, 0u);

    size_t files_in_tmp = count_files(TMP_DIR);
    EXPECT_EQ(files_in_tmp, 0u) << "Dry-run created files in output!";

    std::cout << "  Video batch dry-run: " << r.total << " files"
              << "  projected " << std::fixed << std::setprecision(1)
              << r.savings_pct() << "% saving\n";
}

TEST_F(BPTest, Video_InPlace_ReducesSize) {
    if (skip_if_missing(VID_DIR)) GTEST_SKIP();

    // Clean TMP_DIR first
    fs::remove_all(TMP_DIR);
    fs::create_directories(TMP_DIR);

    // Copy a small video to tmp and process in-place with H.265
    fs::path src = first_file(VID_DIR, ".mp4", 3*1024*1024); // ≤3MB
    if (src.empty()) GTEST_SKIP();

    fs::path copy = TMP_DIR / "inplace.mp4";
    fs::copy_file(src, copy);
    uint64_t orig = fs::file_size(copy);

    VideoConfig cfg;
    cfg.input_dir   = TMP_DIR;
    cfg.output_dir  = "";        // in-place
    cfg.video_codec = VideoCodec::H265;
    cfg.crf         = 28;
    cfg.recursive   = false;

    VideoResult r = process_video(copy, cfg);
    EXPECT_TRUE(r.success) << r.error_msg;

    // Output should be at same path (in-place)
    ASSERT_TRUE(fs::exists(r.output_path)) << "In-place output not found";
    EXPECT_GT(r.output_bytes, 0u);

    std::cout << "  Video In-place: " << orig/1024 << " KB → " 
              << r.output_bytes/1024 << " KB  codec=" 
              << static_cast<int>(r.codec_used) << "\n";
}

TEST_F(BPTest, Video_InPlace_NoExtraFiles) {
    if (skip_if_missing(VID_DIR)) GTEST_SKIP();

    // Clean TMP_DIR first
    fs::remove_all(TMP_DIR);
    fs::create_directories(TMP_DIR);

    // Copy a small video to tmp
    fs::path src = first_file(VID_DIR, ".mp4", 3*1024*1024);
    if (src.empty()) GTEST_SKIP();

    fs::path copy = TMP_DIR / "inplace_test.mp4";
    fs::copy_file(src, copy);

    // Count files before processing
    size_t files_before = count_files(TMP_DIR);

    VideoConfig cfg;
    cfg.input_dir   = TMP_DIR;
    cfg.output_dir  = "";        // in-place
    cfg.video_codec = VideoCodec::H265;
    cfg.recursive   = false;

    VideoResult r = process_video(copy, cfg);
    EXPECT_TRUE(r.success) << r.error_msg;

    // Count files after processing
    size_t files_after = count_files(TMP_DIR);

    // Should have same number of files (1 file processed in-place)
    EXPECT_EQ(files_after, files_before)
        << "In-place processing should not create extra files";

    // Verify no temporary files left behind
    for (const auto& e : fs::recursive_directory_iterator(TMP_DIR)) {
        std::string fname = e.path().filename().string();
        EXPECT_EQ(fname.find(".tmp"), std::string::npos)
            << "Temporary file found after completion: " << e.path();
    }

    std::cout << "  Video In-place: " << files_before << " files before → "
              << files_after << " files after (no extras ✓)\n";
}

